import React from 'react';
import { Link } from 'react-router-dom';
import './MangaCard.css';

const MangaCard = ({ manga }) => {
  return (
    <Link to={`/content/${manga.id}`} className="manga-card">
      <div className="card-image">
        <img src={manga.cover} alt={manga.title} />
        <div className="image-overlay">
          <div className="overlay-content">
            <i className="fas fa-play"></i>
            <span>Читать</span>
          </div>
        </div>
        <div className="card-badge">{manga.type}</div>
      </div>
      
      <div className="card-content">
        <h3 className="card-title">{manga.title}</h3>
        <p className="card-author">{manga.author}</p>
        
        <div className="card-stats">
          <div className="stat">
            <i className="fas fa-star"></i>
            <span>{manga.rating}</span>
          </div>
          <div className="stat">
            <i className="fas fa-book"></i>
            <span>{manga.chapters} гл.</span>
          </div>
          <div className="stat">
            <i className="fas fa-eye"></i>
            <span>{formatNumber(manga.views)}</span>
          </div>
        </div>
      </div>
    </Link>
  );
};

const formatNumber = (num) => {
  if (num >= 1000000) {
    return (num / 1000000).toFixed(1) + 'M';
  }
  if (num >= 1000) {
    return (num / 1000).toFixed(1) + 'K';
  }
  return num.toString();
};

export default MangaCard;
